mapper.select:
	{call P_CUSTOMER_WAR(
			    #{opCode, jdbcType=VARCHAR}
			    , #{contractNum, jdbcType=CLOB}
			    , #{warCd1, jdbcType=VARCHAR}
			    , #{warCd2, jdbcType=VARCHAR}
			    , #{descInfo, jdbcType=VARCHAR}
			    , #{adminId, jdbcType=VARCHAR}
			   ,#{oRetCd, mode=OUT, javaType=string, jdbcType=VARCHAR}
			   ,#{oRetMsg, mode=OUT, javaType=string, jdbcType=VARCHAR}
			  )
     }

SELECT /*+ INDEX_DESC(A PPS_CUSTOMER_WAR_IDX1) ORDERED USE_NL(B)*/ A.CONTRACT_NUM, --C.SUBSCRIBER_NO, SUB_LINK_NAME, SOC, (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC AND ROWNUM = 1) SERVICE_NM, SUB_STATUS, F_GET_KT_CODE_NM('PPS_CUSTOMER', 'SUB_STATUS', SUB_STATUS) SUB_STATUS_NM, TO_CHAR(TO_DATE(LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') LST_COM_ACTV_DATE, DECODE(SUB_STATUS, 'A', '', 'S', TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'), TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD')) SUB_STATUS_DATE, TO_NUMBER(DECODE(C.SUB_STATUS,'A', CEIL(SYSDATE - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'S', CEIL(B.STATUS_STOP_DT - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'C', CEIL(B.STATUS_CANCEL_DT - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')), '')) USE_TERM, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, F_GET_AGENT_NM(AGENT_SALE_ID) AGENT_SALE_NM, F_GET_KT_CODE_NM('CUSTOMER_WAR', 'WAR_CD_1', WAR_CD_1) WAR_CD_1_NM, F_GET_KT_CODE_NM('CUSTOMER_WAR', 'WAR_CD_2', WAR_CD_2) WAR_CD_2_NM, TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS') ENTER_DATE, A.DESC_INFO, A.ADMIN_ID, F_GET_ADMIN_NM(A.ADMIN_ID) ADMIN_NM FROM PPS_CUSTOMER_WAR A, PPS_CUSTOMER B, MSP_JUO_SUB_INFO C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.DEL_YN = 'N'
AND A.ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND A.CONTRACT_NUM = #{searchNm}
AND C.SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND C.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND C.USER_SSN = CRYPTO_AES256.ENC_AES(#{searchNm})
AND WAR_CD_1 = #{searchWarCd1}
AND WAR_CD_2 = #{searchWarCd2}
AND C.SUB_STATUS IN ('A', 'S')
AND C.SUB_STATUS = #{searchSubStatus}

SELECT /*+ INDEX_DESC(A PPS_CUSTOMER_WAR_IDX1) ORDERED USE_NL(B)*/ NVL(A.CONTRACT_NUM, '-') CONTRACT_NUM, --NVL(C.SUBSCRIBER_NO, '-') SUBSCRIBER_NO, NVL(SUB_LINK_NAME, '-') SUB_LINK_NAME, NVL(SOC, '-') SOC, NVL((SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SOC AND ROWNUM = 1), '-') SERVICE_NM, NVL(SUB_STATUS, '-') SUB_STATUS, NVL(F_GET_KT_CODE_NM('PPS_CUSTOMER', 'SUB_STATUS', SUB_STATUS), '-') SUB_STATUS_NM, NVL(TO_CHAR(TO_DATE(LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD'), '-') LST_COM_ACTV_DATE, NVL(DECODE(SUB_STATUS, 'A', '', 'S', TO_CHAR(STATUS_STOP_DT, 'YYYY-MM-DD'), TO_CHAR(STATUS_CANCEL_DT, 'YYYY-MM-DD')), '-') SUB_STATUS_DATE, NVL(TO_NUMBER(DECODE(C.SUB_STATUS,'A', CEIL(SYSDATE - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'S', CEIL(B.STATUS_STOP_DT - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')),'C', CEIL(B.STATUS_CANCEL_DT - TO_DATE(C.LST_COM_ACTV_DATE, 'YYYY-MM-DD')), '')), 0) USE_TERM, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(F_GET_AGENT_NM(AGENT_SALE_ID), '-') AGENT_SALE_NM, NVL(F_GET_KT_CODE_NM('CUSTOMER_WAR', 'WAR_CD_1', WAR_CD_1), '-') WAR_CD_1_NM, NVL(F_GET_KT_CODE_NM('CUSTOMER_WAR', 'WAR_CD_2', WAR_CD_2), '-') WAR_CD_2_NM, NVL(TO_CHAR(A.ENTER_DATE, 'YYYY-MM-DD HH24:MI:SS'), '-') ENTER_DATE, NVL(A.DESC_INFO, '-') DESC_INFO, NVL(A.ADMIN_ID, '-') ADMIN_ID, NVL(F_GET_ADMIN_NM(A.ADMIN_ID), '-') ADMIN_NM FROM PPS_CUSTOMER_WAR A, PPS_CUSTOMER B, MSP_JUO_SUB_INFO C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.DEL_YN = 'N'
AND A.ENTER_DATE >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND A.ENTER_DATE < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND A.CONTRACT_NUM = #{searchNm}
AND C.SUBSCRIBER_NO LIKE '%' || #{searchNm} || '%'
AND C.SUB_LINK_NAME LIKE '%' || #{searchNm} || '%'
AND C.USER_SSN = CRYPTO_AES256.ENC_AES(#{searchNm})
AND WAR_CD_1 = #{searchWarCd1}
AND WAR_CD_2 = #{searchWarCd2}
AND C.SUB_STATUS IN ('A', 'S')
AND C.SUB_STATUS = #{searchSubStatus}
